114	  async ngOnInit() {
115	    try {
116	      const token = localStorage.getItem('token');
117	      if (token) {
118	        const payload = JSON.parse(atob(token.split('.')[1]));
119	        this.userRole = payload.role || null;
120	      }
121	    } catch (e) {
122	      console.warn('Could not parse role from token:', e);
123	    }
