156	      let searchStr = '';
157	      if (typeof searchValue === 'string') {
158	        searchStr = searchValue;
159	      } else if (searchValue && typeof searchValue === 'object' && searchValue.status) {
160	        searchStr = searchValue.status;
161	      } else {
162	        searchStr = '';
163	      }
164	      
165	      this.onStatusSearchChange(searchStr);
166	      
167	      // If user manually clears the search field, clear the form control
168	      const currentStatus = this.form.get('StatusController')?.value;
169	      if (!searchStr && currentStatus) {
170	        this.form.patchValue({ StatusController: '' });
171	      }
172	    });
173	
174	    // Sync search control with form value changes (when status is set programmatically)
175	    this.form.get('StatusController')?.valueChanges.subscribe(selectedStatus => {
176	      if (selectedStatus && selectedStatus.status) {
177	        this.statusSearchControl.setValue(selectedStatus.status, { emitEvent: false });
178	      } else if (!selectedStatus) {
179	        this.statusSearchControl.setValue('', { emitEvent: false });
180	      }
