184	  async onSelectFrom(from){
185	    try {
186	      let item: any = await this.ItemDetailService.getLicenseFeedBacks({from:from}).toPromise();
187	      for (var i = 0; this.data.length > i; i++) {
188	        for (let k = 0; item.length > k; k++) {
189	          if (this.data[i].status == "Request Pre-Pro Sample" && item[k].status == "Request Pre-Pro Sample") {
190	            item[k].disable = true;
191	          } else if (this.data[i].status == "Pre-Pro Submitted" && item[k].status == "Pre-Pro Submitted") {
192	            item[k].disable = true;
193	          } else if (this.data[i].status == "Pre-pro Approved" && item[k].status == "Pre-pro Approved") {
194	            item[k].disable = true;
195	          } else if (this.data[i].status == "Packaging Concept Submitted" && item[k].status == "Packaging Concept Submitted") {
196	            item[k].disable = true;
197	          } else if (this.data[i].status == "Concept Submitted" && item[k].status == "Concept Submitted") {
198	            item[k].disable = true;
199	          } else if (this.data[i].status == "Concept Not Approved at All" && item[k].status == "Concept Not Approved at All") {
200	            item[k].disable = true;
201	          }
202	        }
203	      }
204	
205	      if (this.userRole === 'designer') {
206	        item = item.filter((i: any) => i.status.toLowerCase() === 'ready to submit');
207	      }
208	      this.license_dropdown_data = item;
209	      this.filtered_license_dropdown_data = item;
210	    } catch (err) {
211	      console.error('[FeedbackDialog] getLicenseFeedBacks failed:', err);
212	    }
213	  }
