215	  onStatusSearchChange(searchValue: string): void {
216	    const searchStr = (searchValue || '').toString();
217	    const searchLower = searchStr.toLowerCase().trim();
218	    
219	    if (!searchLower) {
220	      this.filtered_license_dropdown_data = this.license_dropdown_data;
221	      return;
222	    }
223	    
224	    this.filtered_license_dropdown_data = this.license_dropdown_data.filter(item => {
225	      const phase = (item.phase || '').toLowerCase();
226	      const status = (item.status || '').toLowerCase();
227	      return phase.includes(searchLower) || status.includes(searchLower);
228	    });
229	
230	    if (this.userRole === 'designer') {
231	      this.filtered_license_dropdown_data = this.filtered_license_dropdown_data
232	        .filter(item => item.status === 'Ready to Submit');
233	    }
234	  }
