242	  onStatusSelected(event: any): void {
243	    const selectedStatus = event.option.value;
244	    this.form.patchValue({ StatusController: selectedStatus });
245	    // Update search control to show selected status
246	    this.statusSearchControl.setValue(selectedStatus.status || '', { emitEvent: false });
247	  }
