249	  filterUsers(search: string): any[] {
250	    const searchStr = (typeof search === 'string' ? search : '').toLowerCase();
251	    const selectedUsers = Array.isArray(this.form?.value?.AssigneeController)
252	      ? this.form.value.AssigneeController
253	      : [];
254	
255	    if (!searchStr.trim()) {
256	      return this.usersList;
257	    }
258	
259	    const filtered = this.usersList.filter(user => {
260	      const fullName = `${user.name || ''} ${user.lastname || ''}`.toLowerCase();
261	      const email = (user.email || '').toLowerCase();
262	      return fullName.includes(searchStr.trim()) || email.includes(searchStr.trim());
263	    });
264	
265	    return [...filtered, ...selectedUsers].filter((user, index, self) =>
266	      user && index === self.findIndex(u => u?.id === user.id)
267	    );
268	  }
269	
270	  displayUserFn(user: any) {
271	    if (!user) return '';
272	    return `${user.name} ${user.lastname}`;
273	  }
274	
275	  compareUsers(left: any, right: any): boolean {
276	    return (left?.id ?? null) === (right?.id ?? null);
277	  }
278	
279	  clearAssigneeSearch(): void {
