295	  openCreateGroupDialog() {
296	    const dialogRef = this.dialog.open(CreateGroupDialogComponent, {
297	      width: '450px',
298	      data: {}
299	    });
300	
301	    dialogRef.afterClosed().subscribe(result => {
302	      if (result) {
303	        // Refresh groups list
304	        this.licensingService.getAllGroups().subscribe((groups: any) => {
305	          this.groupsList = groups;
306	          // Auto-select the new group
307	          const newGroup = groups.find((g: any) => g.id === result.id);
308	          if (newGroup) {
309	            this.form.patchValue({ GroupController: newGroup });
310	          }
311	        });
312	      }
313	    });
314	  }
315	
316	  getGroupMemberNames(group: any): string {
317	    if (!group || !group.member_user_ids || !this.usersList.length) return '';
318	    
319	    const ids = Array.isArray(group.member_user_ids) ? group.member_user_ids : [];
320	    
321	    const names = ids.map((id: number) => {
322	      const user = this.usersList.find(u => u.id === id);
323	      return user ? `${user.name} ${user.lastname}` : '';
324	    }).filter((n: string) => n);
325	    
326	    return names.length ? `(${names.join(', ')})` : '';
327	  }
