331	  async onSave() {
332	    if (!(this.package && !this.license || !this.package && this.license)) {
333	      this._snakcbar.open('Please select either License or Package.', 'close');
334	      return;
335	    }
336	
337	    // Mark all fields as touched to show validation errors
338	    this.form.markAllAsTouched();
339	
340	    if (this.form.invalid) {
341	      // Check specifically for date validation
342	      if (!this.form.value.dateModifiedControler) {
343	        this._snakcbar.open('Date is required. Please select a date.', 'close');
344	      } else if (!this.form.value.StatusController) {
345	        this._snakcbar.open('Status is required. Please select a status.', 'close');
346	      } else {
347	        this._snakcbar.open('Please fill all required fields.', 'close');
348	      }
349	      return;
350	    }
351	
352	    // Additional validation for date
353	    if (!this.form.value.dateModifiedControler) {
354	      this._snakcbar.open('Date is required. Please select a date.', 'close');
355	      return;
356	    }
357	
358	    this.isSaving = true;
359	    try {
360	      const attachmentsPayload = await this.uploadPendingAttachments();
361	      const selectedAssignees = Array.isArray(this.form.value.AssigneeController)
362	        ? this.form.value.AssigneeController
363	        : (this.form.value.AssigneeController ? [this.form.value.AssigneeController] : []);
364	      const assigneeIds = selectedAssignees.map((user: any) => user?.id).filter(Boolean);
365	      await this.ItemDetailService.AddLicensingStatus({
366	        package: this.package,
367	        itemheader_id_fk: this.itemDetailId,
368	        feedback: (this.form.value.FeedbackController || '').trim(),
369	        pop_comments: (this.form.value.PopCommentsController || '').trim(),
370	        attachments: attachmentsPayload,
371	        status: this.form.value.StatusController.status,
372	        date: this.form.value.dateModifiedControler.toLocaleString('en-US', { timeZone: 'America/New_York' }),
373	        approval: this.form.value.ApprovalController,
374	        from: this.form.value.FromController,
375	        assignee_id: assigneeIds[0],
376	        assignee_ids: assigneeIds,
377	        tagged_group_id: this.form.value.GroupController?.id
378	      }).subscribe({
379	        next: (res: any) => {
380	          if (res.statusCode === 200) {
381	            res.data.package = this.package;
382	            this.dialogRef.close({ data: res.data })
383	          } else {
384	            this._snakcbar.open('Something went wrong', 'close');
385	          }
386	          this.isSaving = false;
387	        },
388	        error: () => {
389	          this.isSaving = false;
390	          this._snakcbar.open('Failed to save feedback', 'close');
391	        },
392	        complete: () => {
393	          this.isSaving = false;
394	        }
395	      })
396	    } catch (err) {
397	      this.isSaving = false;
398	      this._snakcbar.open('Failed to upload attachment. Please try again.', 'close');
399	    }
400	  }
401	
402	  async uploadPendingAttachments(): Promise<AttachmentPayload[]> {
403	    const uploads: AttachmentPayload[] = [];
404	
405	    for (const attachment of this.attachments) {
406	      if (attachment.link) {
407	        uploads.push({
408	          name: attachment.name,
409	          link: attachment.link,
410	          type: attachment.type,
411	          size: attachment.size
412	        });
413	        continue;
414	      }
415	
416	      attachment.status = 'uploading';
417	      const storageName = this.buildStorageFileName(attachment.file);
418	      const contentType = attachment.type || 'application/octet-stream';
419	      await this.helper.saveToDigitalOceanAndDB(storageName, contentType, attachment.file);
420	      const link = this.helper.buildPublicUrl(storageName);
421	      attachment.link = link;
422	      attachment.status = 'uploaded';
423	      uploads.push({
424	        name: attachment.name,
425	        link,
426	        type: attachment.type,
427	        size: attachment.size
428	      });
429	    }
430	
431	    return uploads;
432	  }
433	
434	  buildStorageFileName(file: File): string {
435	    const sanitized = file.name.toLowerCase().replace(/\s+/g, '-');
436	    return `lic-feedback/${this.itemDetailId}/${Date.now()}-${sanitized}`;
437	  }
438	
439	  onFilesSelected(list: FileList | null) {
440	    if (!list) return;
441	    Array.from(list).forEach(file => {
442	      this.attachments.push({
443	        file,
444	        name: file.name,
445	        size: file.size,
446	        type: file.type || 'application/octet-stream',
447	        status: 'pending'
448	      });
449	    });
450	  }
451	
452	  onFileDrop(event: DragEvent) {
453	    event.preventDefault();
454	    const files = event.dataTransfer?.files;
455	    this.onFilesSelected(files || null);
456	  }
457	
458	  onDragOver(event: DragEvent) {
459	    event.preventDefault();
460	  }
461	
462	  removeAttachment(index: number) {
463	    this.attachments.splice(index, 1);
464	  }
465	
466	  formatBytes(bytes: number): string {
467	    if (!bytes) {
468	      return '0 B';
469	    }
470	    const units = ['B', 'KB', 'MB', 'GB'];
471	    const exponent = Math.min(Math.floor(Math.log(bytes) / Math.log(1024)), units.length - 1);
472	    const value = bytes / Math.pow(1024, exponent);
473	    return `${value.toFixed(1)} ${units[exponent]}`;
474	  }
475	
476	  onCancel() {
477	    this.dialogRef.close()
478	  }
479	
480	}

