23	async function attachAssignedUsers(rows) {
24	  const list = Array.isArray(rows) ? rows : [];
25	  const allIds = new Set();
26	
27	  list.forEach(row => {
28	    const plain = row.get ? row.get({ plain: true }) : row;
29	    normalizeIdArray(plain.assignee_ids, plain.assignee_id).forEach(id => allIds.add(id));
30	  });
31	
32	  if (!allIds.size) {
33	    return list.map(row => {
34	      const plain = row.get ? row.get({ plain: true }) : { ...row };
35	      plain.assignee_ids = [];
36	      plain.assignees = [];
37	      plain.assignee = plain.assignee || null;
38	      return plain;
39	    });
40	  }
41	
42	  const users = await sql.users.findAll({
43	    where: { id: { [Op.in]: Array.from(allIds) } },
44	    attributes: ['id', 'name', 'lastname', 'email']
45	  });
46	  const userMap = {};
47	  users.forEach(user => {
48	    const plain = user.get ? user.get({ plain: true }) : user;
49	    userMap[Number(plain.id)] = plain;
50	  });
51	
52	  return list.map(row => {
53	    const plain = row.get ? row.get({ plain: true }) : { ...row };
54	    const ids = normalizeIdArray(plain.assignee_ids, plain.assignee_id);
55	    plain.assignee_ids = ids;
56	    plain.assignees = ids.map(id => userMap[id]).filter(Boolean);
57	    plain.assignee = plain.assignees[0] || plain.assignee || null;
58	    return plain;
59	  });
60	}
